i18n
  .use(LanguageDetector) // Автоматически определяет язык браузера/сохраненный язык
  .use(initReactI18next) // Передает i18n в React
  .init({
    resources,
    fallbackLng: 'et', // Default to Estonian - we are in Estonia!
    detection: {
      order: ['localStorage', 'navigator'], // Приоритет: сначала сохраненный выбор, потом браузер
      caches: ['localStorage'],
      lookupLocalStorage: 'i18nextLng',
    },
    interpolation: {
      escapeValue: false // React уже защищает от XSS
    }
  });

export default i18n;